/* ═══════════════════════════════════════════════════════════════════
   MCP SERVER TAB CONTENT
   ═══════════════════════════════════════════════════════════════════ */
function McpServerTabContent({ tabId, data }: { tabId: string; data: McpServerNodeData }) {
